<?php require_once __DIR__.'/includes/db.php'; require_login(); if($_SERVER['REQUEST_METHOD']==='POST'){ $id=(int)($_POST['user_id']??0); $role=(int)($_POST['role_id']??0); $active=isset($_POST['is_active'])?1:0; if($id>0&&$role>0){ $st=db()->prepare('UPDATE users SET role_id=?, is_active=? WHERE user_id=?'); $st->execute([$role,$active,$id]); }} page_header(tr('users'),'users'); $q=trim($_GET['q']??''); $where='';$params=[]; if($q!==''){ $where='WHERE u.full_name LIKE ? OR u.login LIKE ? OR u.email LIKE ? OR r.role_name LIKE ?'; $like='%'.$q.'%'; $params=[$like,$like,$like,$like]; } $users=rows("SELECT u.*, r.role_name FROM users u JOIN roles r ON r.role_id=u.role_id $where ORDER BY u.user_id DESC",$params); ?><div class="card"><div class="toolbar"><h2><?=h(tr('users'))?></h2><form method="get"><input type="hidden" name="lang" value="<?=h(current_lang())?>"><input class="input" name="q" value="<?=h($q)?>" placeholder="<?=h(tr('search_placeholder'))?>"><button class="btn"><?=h(tr('search'))?></button><a class="btn ghost" href="register.php?lang=<?=h(current_lang())?>"><?=h(tr('register'))?></a></form></div><div class="table-wrap"><table class="table"><thead><tr><th>ID</th><th><?=h(tr('full_name'))?></th><th><?=h(tr('login_name'))?></th><th><?=h(tr('email'))?></th><th><?=h(tr('role'))?></th><th><?=h(tr('active'))?></th><th><?=h(tr('actions'))?></th></tr></thead><tbody><?php foreach($users as $u):?><tr><form method="post"><td><?=h($u['user_id'])?><input type="hidden" name="user_id" value="<?=h($u['user_id'])?>"></td><td><?=h($u['full_name'])?></td><td><?=h($u['login'])?></td><td><?=h($u['email'])?></td><td><select name="role_id"><?=role_options($u['role_id'])?></select></td><td><input type="checkbox" name="is_active" <?=$u['is_active']?'checked':''?>></td><td><button class="btn" type="submit"><?=h(tr('save'))?></button></td></form></tr><?php endforeach;?></tbody></table></div></div><?php page_footer(); ?>